mapper.select:
SELECT t1.ID, t1.ALLOCATE_CODE, t1.TITLE, t1.FROM_COMPANY_ID, t1.FROM_COMPANY_NAME, t1.FROM_WAREHOUSE_ID, t1.FROM_WAREHOUSE_NAME, t1.TO_COMPANY_ID, t1.TO_COMPANY_NAME, t1.TO_WAREHOUSE_ID, t1.TO_WAREHOUSE_NAME, t1.ALLOCATE_TIME, t1.APPLY_USER, t1.APPLY_USER_NAME, t1.APPLY_REASON, t1.EXECUTE_STATUS, t1.EXECUTE_MSG, t1.EXECUTE_TIME, t1.EXECUTE_USER, t1.EXECUTE_USER_NAME, t1.OUT_WAREHOUSE_ID, t1.OUT_WAREHOUSE_NO, t1.IN_WAREHOUSE_ID, t1.IN_WAREHOUSE_NO, t1.REMARKS, t1.CREATE_BY, t1.CREATE_BY_NAME, t1.CREATE_TIME, t1.UPDATE_BY, t1.UPDATE_BY_NAME, t1.UPDATE_TIME, t3.PROC_INST_ID, CASE WHEN t3.INSTANCE_STATUS IS NULL THEN '0' ELSE t3.INSTANCE_STATUS END AS processStatus, CASE WHEN t2.DICT_LABEL IS NULL THEN '未发起' ELSE t2.DICT_LABEL END AS processStatusLabel FROM E_M_MAT_ALLOCATE t1 LEFT JOIN BPM_BUSINESS_INSTANCE t3 ON t3.BUSINESS_DATA_ID = t1.ID LEFT JOIN M_DICT_DATA t2 ON t2.DICT_VALUE = t3.INSTANCE_STATUS AND t2.DICT_TYPE = 'APPROVAL_STATUS'
AND t1.ALLOCATE_CODE LIKE #{allocateCodePattern}
AND t1.TITLE LIKE #{titlePattern}
AND t1.FROM_COMPANY_ID = #{fromCompanyId}
AND t1.FROM_WAREHOUSE_ID = #{fromWarehouseId}
AND t1.TO_COMPANY_ID = #{toCompanyId}
AND t1.TO_WAREHOUSE_ID = #{toWarehouseId}
AND t1.EXECUTE_STATUS = #{executeStatus}
ORDER BY t1.CREATE_TIME DESC

mapper.update:
UPDATE E_M_MAT_ALLOCATE
TITLE = #{title}, FROM_COMPANY_ID = #{fromCompanyId}, FROM_COMPANY_NAME = #{fromCompanyName}, FROM_WAREHOUSE_ID = #{fromWarehouseId}, FROM_WAREHOUSE_NAME = #{fromWarehouseName}, TO_COMPANY_ID = #{toCompanyId}, TO_COMPANY_NAME = #{toCompanyName}, TO_WAREHOUSE_ID = #{toWarehouseId}, TO_WAREHOUSE_NAME = #{toWarehouseName}, ALLOCATE_TIME = #{allocateTime}, APPLY_REASON = #{applyReason}, REMARKS = #{remarks}, UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime},
WHERE ID = #{id}

UPDATE E_M_MAT_ALLOCATE
EXECUTE_STATUS = #{executeStatus}, EXECUTE_MSG = #{executeMsg}, EXECUTE_TIME = #{executeTime}, EXECUTE_USER = #{executeUser}, EXECUTE_USER_NAME = #{executeUserName}, OUT_WAREHOUSE_ID = #{outWarehouseId}, OUT_WAREHOUSE_NO = #{outWarehouseNo}, IN_WAREHOUSE_ID = #{inWarehouseId}, IN_WAREHOUSE_NO = #{inWarehouseNo}, UPDATE_BY = #{updateBy}, UPDATE_BY_NAME = #{updateByName}, UPDATE_TIME = #{updateTime},
WHERE ID = #{id}
